function getScrollPos(){return window.scrollY||document.documentElement.scrollTop}function isElementInViewport(e,t=.2){if(!e)return!1;const n=e.getBoundingClientRect(),o=window.innerHeight||document.documentElement.clientHeight;return n.top<=o*(1-t)&&n.bottom>=o*t}function throttle(e,t){let n=!1;return function(...o){n||(n=!0,e.apply(this,o),setTimeout(()=>{n=!1},t))}}function debounce(e,t){let n;return function(...o){clearTimeout(n),n=setTimeout(()=>e.apply(this,o),t)}}function formatNumber(e){return new Intl.NumberFormat("en-IN").format(e)}function animateCounter(e,t,n=1800){const o=performance.now();requestAnimationFrame(function r(i){const u=i-o,c=Math.min(u/n,1),a=1-Math.pow(1-c,3),m=Math.floor(0+(t-0)*a);e.textContent=formatNumber(m),c<1&&requestAnimationFrame(r)})}function saveDarkModePreference(e){localStorage.setItem("impulse-theme",e?"dark":"light")}function loadDarkModePreference(){const e=localStorage.getItem("impulse-theme");return!!e&&"dark"===e}function toggleDarkMode(){const e=document.body.classList.toggle("light-mode");return saveDarkModePreference(!e),!e}function validateEmail(e){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(e).trim())}function validateForm(e){return e.name&&validateEmail(e.email)&&e.service&&e.message}function $(e,t=document){return t.querySelector(e)}function $$(e,t=document){return Array.from(t.querySelectorAll(e))}